UPDATE review
SET status = 1
WHERE id = #{id}

UPDATE review
SET status = 0
WHERE id = #{id}

mapper.select:
SELECT r.id, u.nickname AS userNickname, r.content, r.like_count, r.reply_count, r.status, r.create_time, r.update_time FROM review r LEFT JOIN user u ON r.user_id = u.id
AND u.nickname LIKE concat('%', #{userNickname}, '%')
AND r.movie_id = #{movieId}
AND r.status = #{status}
ORDER BY r.id DESC
